// Haalt de bonusaanbiedingen uit de JSON die ah.nl in de pagina insluit (window.__INITIAL_STATE__).
// Onofficiële bron: als AH de structuur wijzigt, geeft deze node een duidelijke fout.
const html = String($input.first().json.data || '');
const marker = 'window.__INITIAL_STATE__=';
const start = html.indexOf(marker);
if (start === -1) {
  throw new Error('Kon window.__INITIAL_STATE__ niet vinden op ah.nl/bonus — structuur gewijzigd of verzoek geblokkeerd.');
}
const rest = html.slice(start + marker.length);
const end = rest.indexOf('</script>');
let raw = (end === -1 ? rest : rest.slice(0, end)).trim();
if (raw.endsWith(';')) raw = raw.slice(0, -1);
raw = raw.replace(/:undefined([,}\]])/g, ':null$1');
let state;
try {
  state = JSON.parse(raw);
} catch (e) {
  throw new Error('Kon de AH-bonusdata niet als JSON lezen: ' + e.message);
}

const offers = [];
const seen = new Set();
const vandaag = new Date().toISOString().slice(0, 10);

function walk(o, diepte) {
  if (!o || typeof o !== 'object' || diepte > 25) return;
  if (Array.isArray(o)) { for (const v of o) walk(v, diepte + 1); return; }
  const title = o.title || o.shortTitle;
  const mech = o.bonusMechanism || o.discountLabel || o.discountDescription
    || (o.discount && typeof o.discount === 'object' ? (o.discount.description || o.discount.label || o.discount.theme) : null);
  if (typeof title === 'string' && title.length > 1 && typeof mech === 'string' && mech.length > 0) {
    const key = (title + '|' + mech).toLowerCase();
    if (!seen.has(key)) {
      seen.add(key);
      let prijs = '';
      if (o.price && typeof o.price === 'object') { prijs = o.price.now ?? o.price.bonus ?? ''; }
      else if (o.bonusPrice != null) { prijs = o.bonusPrice; }
      const geldig = o.validUntil || o.bonusEndDate || o.endDate || '';
      offers.push({
        winkel: 'AH',
        product: title,
        prijs: String(prijs ?? ''),
        korting: mech,
        geldig_tot: String(geldig).slice(0, 10),
        opgehaald_op: vandaag,
      });
    }
  }
  for (const v of Object.values(o)) walk(v, diepte + 1);
}
walk(state, 0);

if (!offers.length) {
  throw new Error('Geen aanbiedingen gevonden in de AH-data — structuur waarschijnlijk gewijzigd.');
}
return [{ json: { winkel: 'AH', aantal: offers.length, aanbiedingen: offers } }];

// plus.nl zelf rendert client-side; daarom gebruiken we een server-gerenderde aggregatorpagina
// en laten we Gemini de aanbiedingen uit de kale tekst halen.
let html = String($input.first().json.data || '');
html = html.replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ');
let tekst = html
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/&euro;/gi, '€')
  .replace(/\s+/g, ' ')
  .trim();
if (tekst.length < 500) {
  throw new Error('De Plus-aanbiedingenpagina leverde te weinig tekst op — structuur gewijzigd of verzoek geblokkeerd.');
}
return [{ json: { tekst: tekst.slice(0, 60000) } }];

