const uit = $input.first().json.output || $input.first().json;
const lijst = (uit.aanbiedingen || []).filter(a => a && a.product);
if (!lijst.length) {
  throw new Error('Geen Plus-aanbiedingen kunnen extraheren uit de pagina.');
}
const vandaag = new Date().toISOString().slice(0, 10);
const offers = lijst.map(a => ({
  winkel: 'Plus',
  product: String(a.product).trim(),
  prijs: String(a.prijs || '').trim(),
  korting: String(a.korting || '').trim(),
  geldig_tot: String(a.geldig_tot || '').trim(),
  opgehaald_op: vandaag,
}));
return [{ json: { winkel: 'Plus', aantal: offers.length, aanbiedingen: offers } }];

const inst = $('Instellingen aanbiedingen').first().json;
const chatId = String(inst.chatId || '').trim();
if (!chatId) { return []; } // geen chat-id ingesteld → stil eindigen

function veilig(naam) {
  try { return $(naam).first().json; } catch (e) { return null; }
}
const ah = veilig('AH parsen');
const plus = veilig('Plus normaliseren');
const offers = [
  ...((ah && ah.aanbiedingen) || []),
  ...((plus && plus.aanbiedingen) || []),
];

// 'Vaak gekocht' = items die 2+ keer op een lijst hebben gestaan
const historie = $input.all().map(i => i.json).filter(r => r && r.tekst);
const freq = {};
for (const r of historie) {
  const t = String(r.tekst).toLowerCase().trim();
  if (t.length > 2) { freq[t] = (freq[t] || 0) + 1; }
}
const vaak = Object.entries(freq).filter(([, n]) => n >= 2).map(([t]) => t);

const matches = [];
for (const o of offers) {
  const p = String(o.product).toLowerCase();
  for (const v of vaak) {
    if (p.includes(v) || v.includes(p)) {
      matches.push(`• [${o.winkel}] ${o.product}${o.korting ? ' — ' + o.korting : ''}`);
      break;
    }
  }
}

const delen = [];
delen.push(`🛒 Aanbiedingen opgehaald: ${ah ? ah.aantal + ' van AH' : 'AH mislukt'}, ${plus ? plus.aantal + ' van Plus' : 'Plus mislukt'}.`);
if (matches.length) {
  delen.push(`\nDeze week in de aanbieding van jullie vaste boodschappen:\n${[...new Set(matches)].join('\n')}`);
} else {
  delen.push('\nGeen van jullie vaste boodschappen is deze week in de aanbieding (of er is nog te weinig boodschappenhistorie).');
}
delen.push('\nVraag me gerust: "is er ... in de aanbieding?" of "wat eten we deze week?"');
return [{ json: { chatId, tekst: delen.join('\n') } }];

const inst = $('Instellingen aanbiedingen').first().json;
const chatId = String(inst.chatId || '').trim();
if (!chatId) { return []; }
const meldingen = $input.all().map(i => {
  const e = i.json.error;
  if (e && typeof e === 'object') { return e.message || JSON.stringify(e); }
  return String(e || i.json.message || 'onbekende fout');
});
return [{ json: { chatId, tekst: `⚠️ Het ophalen van de aanbiedingen is (deels) mislukt:\n${[...new Set(meldingen)].map(m => '• ' + m).join('\n')}\n\nZie de uitvoeringsdetails in n8n.` } }];
